import React from 'react';
import './TopProducts.css';

const products = [
  { name: 'Nexus Pro X1', sales: 8420, revenue: 84200, pct: 92, color: '#7c6af7' },
  { name: 'CloudBase Suite', sales: 5640, revenue: 56400, pct: 71, color: '#22d3ee' },
  { name: 'DataStream API', sales: 4120, revenue: 41200, pct: 56, color: '#f97316' },
  { name: 'Vision Analytics', sales: 3280, revenue: 32800, pct: 43, color: '#a3e635' },
  { name: 'CoreEdge Lite', sales: 2140, revenue: 21400, pct: 28, color: '#f472b6' },
];

export default function TopProducts() {
  return (
    <div className="card top-products">
      <div className="card-title">Top Products</div>
      <div className="products-list">
        {products.map((p, i) => (
          <div className="product-row" key={p.name}>
            <div className="product-rank">{String(i + 1).padStart(2, '0')}</div>
            <div className="product-info">
              <div className="product-name">{p.name}</div>
              <div className="product-bar-track">
                <div className="product-bar-fill" style={{ width: `${p.pct}%`, background: p.color }} />
              </div>
            </div>
            <div className="product-stats">
              <div className="product-revenue">${(p.revenue / 1000).toFixed(0)}k</div>
              <div className="product-sales">{p.sales.toLocaleString()} units</div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}
